mapper.select:
SELECT s.ID AS studentId, s.name, s.name_kana AS nameKana, sc.id_bigint AS studentCourseId, sc.course_name AS courseName, cs.course_status AS courseStatus FROM students s LEFT JOIN students_courses sc ON s.ID = sc.students_ID LEFT JOIN course_status cs ON sc.id_bigint = cs.student_course_id
AND s.is_deleted = 0
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.name_kana LIKE CONCAT('%', #{nameKana}, '%')
AND s.ID = #{id}
AND sc.id_bigint = #{studentCourseId}
AND sc.course_name = #{courseName}
AND cs.course_status = #{courseStatus}
